import React from 'react';
import {
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper,
  Button,
  Stack,
  Chip,
  Box,
  Typography,
  Avatar,
  Card,
  CardContent,
  useTheme,
  alpha,
  Tooltip,
  IconButton,
} from '@mui/material';
import {
  AssignmentLate as AssignmentLateIcon,
  CheckCircle as ApproveIcon,
  Cancel as RejectIcon,
  Schedule as TimeIcon,
  Person as PersonIcon,
  Assignment as ProjectIcon,
  AccessTime as ClockIcon,
  CheckCircleOutline as StatusIcon,
} from '@mui/icons-material';
import dayjs from 'dayjs';
import { OT_STATUS } from 'utils/constants';

export default function OtCheckRe({
  timestamp,
  renderApprove,
  renderReject,
  renderCancel,
}) {
  const theme = useTheme();
  const hasData = timestamp?.rows && timestamp.rows.length > 0;

  const calculateHours = (startTime, endTime) => {
    return dayjs(endTime).diff(dayjs(startTime), 'hour', true).toFixed(1);
  };

  const getStatusColor = (status) => {
    return OT_STATUS?.[status]?.color || 'default';
  };

  const getStatusLabel = (status) => {
    return OT_STATUS?.[status]?.status_code || status;
  };

  if (!hasData) {
    return (
      <Card variant="outlined" sx={{ borderRadius: 2 }}>
        <CardContent sx={{ py: 6, textAlign: 'center' }}>
          <AssignmentLateIcon
            sx={{ fontSize: 64, color: 'text.disabled', mb: 2 }}
          />
          <Typography variant="h6" color="text.secondary" gutterBottom>
            ไม่มีรายการรออนุมัติ
          </Typography>
          <Typography variant="body2" color="text.secondary">
            ไม่พบข้อมูลการขอ OT ที่รออนุมัติในขณะนี้
          </Typography>
        </CardContent>
      </Card>
    );
  }

  return (
    <Card variant="outlined" sx={{ borderRadius: 2 }}>
      <TableContainer>
        <Table>
          <TableHead>
            <TableRow sx={{ bgcolor: theme.palette.primary.main }}>
              <TableCell
                sx={{ color: '#FFFFFF', width: 60, minWidth: 60, maxWidth: 70 }}
              >
                ลำดับ
              </TableCell>
              <TableCell
                sx={{
                  color: '#FFFFFF',
                  width: 120,
                  minWidth: 100,
                  maxWidth: 140,
                }}
              >
                ผู้ทำรายการ
              </TableCell>
              <TableCell
                sx={{
                  color: '#FFFFFF',
                  width: 160,
                  minWidth: 120,
                  maxWidth: 180,
                }}
              >
                พนักงาน
              </TableCell>
              <TableCell
                sx={{
                  color: '#FFFFFF',
                  width: 120,
                  minWidth: 100,
                  maxWidth: 140,
                }}
              >
                โปรเจค
              </TableCell>
              <TableCell
                sx={{
                  color: '#FFFFFF',
                  width: 180,
                  minWidth: 140,
                  maxWidth: 220,
                }}
              >
                รายละเอียด
              </TableCell>
              <TableCell
                sx={{
                  color: '#FFFFFF',
                  width: 110,
                  minWidth: 90,
                  maxWidth: 120,
                }}
              >
                วันที่
              </TableCell>
              <TableCell
                sx={{
                  color: '#FFFFFF',
                  width: 110,
                  minWidth: 90,
                  maxWidth: 120,
                }}
              >
                เวลา / ชั่วโมง
              </TableCell>
              <TableCell
                sx={{
                  color: '#FFFFFF',
                  width: 120,
                  minWidth: 100,
                  maxWidth: 140,
                }}
              >
                สถานะ / ผู้อนุมัติ
              </TableCell>
              <TableCell
                align="center"
                sx={{
                  color: '#FFFFFF',
                  width: 80,
                  minWidth: 60,
                  maxWidth: 90,
                }}
              >
                จัดการ
              </TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {timestamp.rows.map((row, index) => (
              <TableRow
                key={row.id}
                sx={{
                  '&:hover': {
                    bgcolor: alpha(theme.palette.primary.main, 0.02),
                  },
                }}
              >
                {/* ลำดับ */}
                <TableCell align="center">
                  <Typography variant="body2" fontWeight={500}>
                    {index + 1}
                  </Typography>
                </TableCell>

                {/*ผู้ทำรายการ*/}
                <TableCell>
                  <Typography variant="body2" fontWeight={500}>
                    {row?.resquester?.firstname} {row?.resquester?.lastname}
                  </Typography>
                </TableCell>

                {/* พนักงาน */}
                <TableCell>
                  <Box>
                    {_?.map(row?.ot_lists, (e, idx) => (
                      <Typography key={idx} variant="body2" fontWeight={500}>
                        {idx + 1}. {e?.employee_name}
                      </Typography>
                    ))}
                  </Box>
                </TableCell>

                {/* โปรเจค */}
                <TableCell>
                  <Typography variant="body2" fontWeight={500}>
                    {row?.project?.project_number || 'N/A'}
                  </Typography>
                  <Typography variant="caption" color="text.secondary">
                    {row?.project?.name || 'ไม่ระบุโปรเจค'}
                  </Typography>
                </TableCell>

                {/* รายละเอียด */}
                <TableCell>
                  {row?.status_claim && (
                    <Chip
                      label={'ขอโอทีย้อนหลัง'}
                      size="small"
                      color="error"
                      sx={{ mb: 0.5 }}
                    />
                  )}
                  <Typography variant="body2">
                    สาเหตุ: {row?.description || 'ไม่มีรายละเอียด'}
                  </Typography>
                </TableCell>

                {/* วันที่ */}
                <TableCell align="center">
                  <Typography variant="body2" fontWeight={600}>
                    {dayjs(row?.date).format('DD/MM/YYYY')}
                  </Typography>
                </TableCell>

                {/* เวลา / ชั่วโมง */}
                <TableCell align="center">
                  <Typography variant="body2" fontWeight={600}>
                    {dayjs(row?.startTime).format('HH:mm')} -{' '}
                    {dayjs(row?.endTime).format('HH:mm')}
                  </Typography>
                  <Chip
                    label={`${calculateHours(
                      row?.startTime,
                      row?.endTime,
                    )} ชม.`}
                    size="small"
                    color="info"
                    variant="outlined"
                    sx={{ fontWeight: 500, mt: 0.5 }}
                  />
                </TableCell>

                {/* สถานะ / ผู้อนุมัติ */}
                <TableCell>
                  <Stack spacing={0.5}>
                    <Chip
                      label={getStatusLabel(row?.status)}
                      color={getStatusColor(row?.status)}
                      size="small"
                      variant="filled"
                      sx={{ fontSize: '0.7rem' }}
                    />

                    {/* ผู้อนุมัติ */}
                    {row?.approver ? (
                      <Typography
                        variant="caption"
                        fontWeight={500}
                        sx={{
                          fontSize: '0.7rem',
                          overflow: 'hidden',
                          textOverflow: 'ellipsis',
                          whiteSpace: 'nowrap',
                          maxWidth: 120,
                        }}
                      >
                        {row?.approver?.firstname} {row?.approver?.lastname}
                      </Typography>
                    ) : (
                      <Typography
                        variant="caption"
                        color="text.secondary"
                        sx={{ fontSize: '0.7rem' }}
                      >
                        รออนุมัติ
                      </Typography>
                    )}
                  </Stack>
                </TableCell>

                {/* ปุ่มจัดการ */}
                <TableCell align="center">
                  {row?.status === 'PENDING' ? (
                    <Stack direction="row" spacing={1} justifyContent="center">
                      <Tooltip title="อนุมัติ">
                        <IconButton
                          color="success"
                          size="small"
                          onClick={() => renderApprove(row)}
                          sx={{
                            bgcolor: alpha(theme.palette.success.main, 0.1),
                            '&:hover': {
                              bgcolor: alpha(theme.palette.success.main, 0.2),
                            },
                          }}
                        >
                          <ApproveIcon fontSize="small" />
                        </IconButton>
                      </Tooltip>
                      <Tooltip title="ปฏิเสธ">
                        <IconButton
                          color="error"
                          size="small"
                          onClick={() => renderReject(row)}
                          sx={{
                            bgcolor: alpha(theme.palette.error.main, 0.1),
                            '&:hover': {
                              bgcolor: alpha(theme.palette.error.main, 0.2),
                            },
                          }}
                        >
                          <RejectIcon fontSize="small" />
                        </IconButton>
                      </Tooltip>
                    </Stack>
                  ) : (
                    <Button
                      variant="outlined"
                      color="warning"
                      size="small"
                      onClick={() => renderCancel(row)}
                    >
                      ยกเลิก
                    </Button>
                  )}
                </TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </TableContainer>
    </Card>
  );
}
