import React, { useState, useEffect } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import * as actions from '../../redux/actions';
import dayjs from 'dayjs';
import _ from 'lodash';

// Material UI
import {
  Box,
  Button,
  Card,
  Grid,
  Typography,
  Paper,
  Divider,
  Stack,
  IconButton,
  Chip,
  TextField,
  MenuItem,
  InputAdornment,
  Container,
  useTheme,
  alpha,
  Fade,
  Collapse,
  Popover,
  Tooltip,
  Menu,
  ListItemIcon,
  ListItemText,
  ToggleButtonGroup,
  ToggleButton,
} from '@mui/material';

// Icons
import CalendarTodayIcon from '@mui/icons-material/CalendarToday';
import NavigateBeforeIcon from '@mui/icons-material/NavigateBefore';
import NavigateNextIcon from '@mui/icons-material/NavigateNext';
import PrintIcon from '@mui/icons-material/Print';
import PeopleIcon from '@mui/icons-material/People';
import BusinessIcon from '@mui/icons-material/Business';
import WorkIcon from '@mui/icons-material/Work';
import FilterAltIcon from '@mui/icons-material/FilterAlt';
import FilterAltOffIcon from '@mui/icons-material/FilterAltOff';
import DescriptionIcon from '@mui/icons-material/Description';
import AttachMoneyIcon from '@mui/icons-material/AttachMoney';
import TimelineIcon from '@mui/icons-material/Timeline';
import TodayIcon from '@mui/icons-material/Today';
import MoreVertIcon from '@mui/icons-material/MoreVert';

// Components
import { ViewTitle } from 'components/ViewTitle';
import HrDashboardCard from '../../components/Card/HrDashboardCard';
import HrcheckinListReportDailyByproject from '../../components/Table/HrcheckinListReportDailyByproject';
import { AdapterDayjs } from '@mui/x-date-pickers/AdapterDayjs';
import { LocalizationProvider } from '@mui/x-date-pickers/LocalizationProvider';
import { DatePicker } from '@mui/x-date-pickers/DatePicker';
import { Loading } from '../../components/Loading';

// PDF Generation
import {
  timestampCheckinReport,
  timestampDailyReport,
  timestampDailySalaryReport,
  timestampDailyAllProjectReport,
  timestampDailySalaryAllProjectReport,
} from '../../components/PDF';

export default function HrReportDaily({ title, subtitle }) {
  const theme = useTheme();
  const dispatch = useDispatch();

  // Selectors
  const timestamp = useSelector((state) => state.timestamp);
  const employees = useSelector((state) => state.employee);
  const project = useSelector((state) => state.project);
  const roletype = useSelector((state) => state.roletype);
  const me = useSelector((state) => state.me);

  const am = me?.userData;

  // States
  const [page, setPage] = useState(1);
  const [size, setSize] = useState(30);
  const [emSelect, setEmSelect] = useState();
  const [projectSelect, setProjectSelect] = useState();
  const [dateStart, setDateStart] = useState(dayjs());
  const [dateEnd, setDateEnd] = useState(new Date());
  const [selectedIndex, setSelectedIndex] = useState(0);
  const [roleSelect, setRoleSelect] = useState();
  const [filterAnchorEl, setFilterAnchorEl] = useState(null);
  const [datePickerOpen, setDatePickerOpen] = useState(false);
  const [dateAnchorEl, setDateAnchorEl] = useState(null);
  const [reportTypeAnchorEl, setReportTypeAnchorEl] = useState(null);
  const [printMenuAnchorEl, setPrintMenuAnchorEl] = useState(null);

  const reportTypes = [
    {
      id: 0,
      label: 'Without Salary',
      icon: <DescriptionIcon />,
      color: 'success',
      permission: true,
    },
    {
      id: 1,
      label: 'With Salary',
      icon: <AttachMoneyIcon />,
      color: 'secondary',
      permission: am?.permissions?.hr_management || false,
    },
    {
      id: 2,
      label: 'Checkin',
      icon: <TimelineIcon />,
      color: 'info',
      permission: am?.permissions?.hr_management || false,
    },
  ];

  // Computed states
  const groupProject = _?.groupBy(timestamp?.rows, 'projectDetails._id');
  const activeFiltersCount = [emSelect, projectSelect, roleSelect].filter(
    Boolean,
  ).length;
  const formattedDate = dayjs(dateStart).format('DD MMM YYYY');

  // Load data
  useEffect(() => {
    dispatch(actions.timestampReset());
    dispatch(
      actions.timestampDaily({
        dateStart: dayjs(dateStart).startOf('day').toISOString(),
        dateEnd: dayjs(dateStart).endOf('day').toISOString(),
      }),
    );
    return () => {};
  }, [
    page,
    size,
    emSelect,
    dateStart,
    dateEnd,
    projectSelect,
    roleSelect,
    selectedIndex,
  ]);

  // Load initial data
  useEffect(() => {
    dispatch(actions.projectAll({}));
    dispatch(actions.employeeAll({}));
    dispatch(actions.getInformation());
    dispatch(actions.roletypeAll({}));
    return () => {};
  }, []);

  // Handlers
  const handlePrint = () => {
    const data = { ...timestamp, project: projectSelect, date: dateStart };
    timestampDailyAllProjectReport(data);
    setPrintMenuAnchorEl(null);
  };

  const handlePrintWithSalary = () => {
    const data = { ...timestamp, project: projectSelect, date: dateStart };
    timestampDailySalaryAllProjectReport(data);
    setPrintMenuAnchorEl(null);
  };

  const handlePrintCheckin = () => {
    const data = { ...timestamp, project: projectSelect, date: dateStart };
    timestampCheckinReport(data);
    setPrintMenuAnchorEl(null);
  };

  const handlePrintReport = () => {
    if (selectedIndex === 0) {
      handlePrint();
    } else if (selectedIndex === 1) {
      handlePrintWithSalary();
    } else {
      handlePrintCheckin();
    }
  };

  const goToPreviousDay = () => {
    const newDate = dayjs(dateStart).subtract(1, 'day');
    setDateStart(newDate);
  };

  const goToNextDay = () => {
    const newDate = dayjs(dateStart).add(1, 'day');
    setDateStart(newDate);
  };

  const clearFilters = () => {
    setEmSelect(undefined);
    setProjectSelect(undefined);
    setRoleSelect(undefined);
    setFilterAnchorEl(null);
  };

  const openFiltersMenu = (event) => {
    setFilterAnchorEl(event.currentTarget);
  };

  const closeFiltersMenu = () => {
    setFilterAnchorEl(null);
  };

  const openDatePicker = (event) => {
    setDateAnchorEl(event.currentTarget);
    setDatePickerOpen(true);
  };

  const closeDatePicker = () => {
    setDateAnchorEl(null);
    setDatePickerOpen(false);
  };

  const openReportTypeMenu = (event) => {
    setReportTypeAnchorEl(event.currentTarget);
  };

  const closeReportTypeMenu = () => {
    setReportTypeAnchorEl(null);
  };

  const openPrintMenu = (event) => {
    setPrintMenuAnchorEl(event.currentTarget);
  };

  const closePrintMenu = () => {
    setPrintMenuAnchorEl(null);
  };

  const handleNotifyHr = () => {
    const confirm = window.confirm('Are you sure to send notification to HR?');
    if (confirm) {
      dispatch(
        actions.requestNotifyCheckinDaily({
          date: dayjs(dateStart).format('YYYY-MM-DD'),
        }),
      );
    }
  };

  // Render compact header (reorganized)
  const renderCompactHeader = () => (
    <Box
      sx={{
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'space-between',
        flexWrap: 'wrap',
        gap: 1,
        mb: 2,
      }}
    >
      {/* Left: Date navigation */}
      <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
        <Box
          sx={{
            display: 'flex',
            alignItems: 'center',
            border: '1px solid',
            borderColor: 'divider',
            borderRadius: 1,
            bgcolor: 'background.paper',
            overflow: 'hidden',
          }}
        >
          <Tooltip title="Previous day">
            <IconButton
              size="small"
              onClick={goToPreviousDay}
              sx={{ borderRadius: 0 }}
            >
              <NavigateBeforeIcon fontSize="small" />
            </IconButton>
          </Tooltip>

          <Tooltip title="Select date">
            <Button
              size="small"
              onClick={openDatePicker}
              sx={{
                px: 1,
                py: 0.5,
                borderRadius: 0,
                border: 'none',
                borderLeft: '1px solid',
                borderRight: '1px solid',
                borderColor: 'divider',
              }}
              startIcon={<CalendarTodayIcon fontSize="small" />}
            >
              {formattedDate}
            </Button>
          </Tooltip>

          <Tooltip title="Next day">
            <IconButton
              size="small"
              onClick={goToNextDay}
              sx={{ borderRadius: 0 }}
            >
              <NavigateNextIcon fontSize="small" />
            </IconButton>
          </Tooltip>
        </Box>
      </Box>

      {/* Center: Report type selector (prominent) */}
      <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
        <ToggleButtonGroup
          value={selectedIndex}
          exclusive
          size="small"
          onChange={(e, value) => value !== null && setSelectedIndex(value)}
        >
          {reportTypes.map(
            (type) =>
              type.permission && (
                <ToggleButton
                  key={type.id}
                  value={type.id}
                  color={type.color}
                  sx={{ px: 1, py: 0.5 }}
                >
                  <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
                    {React.cloneElement(type.icon, { fontSize: 'small' })}
                    <Typography
                      variant="body2"
                      sx={{ display: { xs: 'none', sm: 'block' } }}
                    >
                      {type.label}
                    </Typography>
                  </Box>
                </ToggleButton>
              ),
          )}
        </ToggleButtonGroup>
      </Box>

      {/* Right: Notify + Filters + Print (grouped) */}
      <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
        {/* Quick notify button moved to right */}
        <Button
          size="small"
          variant="outlined"
          onClick={handleNotifyHr}
          sx={{ ml: 0 }}
        >
          Notify HR
        </Button>

        <Tooltip
          title={
            activeFiltersCount > 0
              ? `${activeFiltersCount} filters active`
              : 'Filter'
          }
        >
          <Button
            size="small"
            onClick={openFiltersMenu}
            variant={activeFiltersCount > 0 ? 'contained' : 'outlined'}
            color={activeFiltersCount > 0 ? 'primary' : 'inherit'}
            startIcon={<FilterAltIcon />}
            sx={{ py: 0.5 }}
          >
            <Box sx={{ display: { xs: 'none', sm: 'block' } }}>
              {activeFiltersCount > 0
                ? `Filters (${activeFiltersCount})`
                : 'Filter'}
            </Box>
          </Button>
        </Tooltip>

        <Tooltip title="Print report">
          <Button
            size="small"
            variant="contained"
            color={reportTypes[selectedIndex].color}
            onClick={handlePrintReport}
            startIcon={<PrintIcon />}
            sx={{ py: 0.5 }}
          >
            <Box sx={{ display: { xs: 'none', sm: 'block' } }}>Print</Box>
          </Button>
        </Tooltip>

        {/* More actions menu (optional) */}
        <IconButton size="small" onClick={openPrintMenu}>
          <MoreVertIcon />
        </IconButton>
      </Box>

      {/* Date Picker Popover */}
      <Popover
        open={datePickerOpen}
        anchorEl={dateAnchorEl}
        onClose={closeDatePicker}
        anchorOrigin={{
          vertical: 'bottom',
          horizontal: 'left',
        }}
      >
        <Paper sx={{ p: 2, width: 300 }}>
          <LocalizationProvider dateAdapter={AdapterDayjs}>
            <DatePicker
              value={dateStart}
              onChange={(newDate) => {
                setDateStart(newDate);
                closeDatePicker();
              }}
              renderInput={(props) => (
                <TextField {...props} fullWidth size="small" />
              )}
            />
          </LocalizationProvider>

          <Box sx={{ display: 'flex', justifyContent: 'space-between', mt: 2 }}>
            <Button
              size="small"
              startIcon={<TodayIcon />}
              onClick={() => {
                setDateStart(dayjs());
                closeDatePicker();
              }}
            >
              Today
            </Button>
            <Button size="small" onClick={closeDatePicker}>
              Close
            </Button>
          </Box>
        </Paper>
      </Popover>

      {/* Filters Menu */}
      <Popover
        open={Boolean(filterAnchorEl)}
        anchorEl={filterAnchorEl}
        onClose={closeFiltersMenu}
        anchorOrigin={{
          vertical: 'bottom',
          horizontal: 'left',
        }}
      >
        <Paper sx={{ p: 2, width: 300 }}>
          <Typography variant="subtitle2" gutterBottom>
            Filter Report
          </Typography>
          <Divider sx={{ mb: 2 }} />

          <Stack spacing={2}>
            <TextField
              select
              label="Employee"
              size="small"
              fullWidth
              value={emSelect?._id || ''}
              onChange={(e) =>
                setEmSelect(
                  e.target.value
                    ? employees?.rows?.find((em) => em._id === e.target.value)
                    : undefined,
                )
              }
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <PeopleIcon fontSize="small" color="action" />
                  </InputAdornment>
                ),
              }}
            >
              <MenuItem value="">All Employees</MenuItem>
              {employees?.rows?.map((employee) => (
                <MenuItem key={employee._id} value={employee._id}>
                  {employee.firstname} {employee.lastname}
                </MenuItem>
              ))}
            </TextField>

            <TextField
              select
              label="Project"
              size="small"
              fullWidth
              value={projectSelect?._id || ''}
              onChange={(e) =>
                setProjectSelect(
                  e.target.value
                    ? project?.rows?.find((p) => p._id === e.target.value)
                    : undefined,
                )
              }
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <BusinessIcon fontSize="small" color="action" />
                  </InputAdornment>
                ),
              }}
            >
              <MenuItem value="">All Projects</MenuItem>
              {project?.rows?.map((proj) => (
                <MenuItem key={proj._id} value={proj._id}>
                  {proj.name}
                </MenuItem>
              ))}
            </TextField>

            <TextField
              select
              label="Role"
              size="small"
              fullWidth
              value={roleSelect?._id || ''}
              onChange={(e) =>
                setRoleSelect(
                  e.target.value
                    ? roletype?.rows?.find(
                        (role) => role._id === e.target.value,
                      )
                    : undefined,
                )
              }
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <WorkIcon fontSize="small" color="action" />
                  </InputAdornment>
                ),
              }}
            >
              <MenuItem value="">All Roles</MenuItem>
              {roletype?.rows?.map((role) => (
                <MenuItem key={role._id} value={role._id}>
                  {role.name}
                </MenuItem>
              ))}
            </TextField>
          </Stack>

          <Box
            sx={{ display: 'flex', justifyContent: 'flex-end', mt: 2, gap: 1 }}
          >
            {activeFiltersCount > 0 && (
              <Button
                size="small"
                startIcon={<FilterAltOffIcon />}
                onClick={clearFilters}
                color="inherit"
              >
                Clear All
              </Button>
            )}
            <Button size="small" variant="contained" onClick={closeFiltersMenu}>
              Apply
            </Button>
          </Box>
        </Paper>
      </Popover>
    </Box>
  );

  // Render report content
  const renderTable = () => {
    // Dashboard view
    if (selectedIndex === 2) {
      return (
        <Fade in={true} timeout={300}>
          <Card
            elevation={0}
            sx={{
              borderRadius: 1,
              border: '1px solid',
              borderColor: 'divider',
            }}
          >
            <Box
              sx={{
                p: 1.5,
                borderBottom: '1px solid',
                borderColor: 'divider',
                bgcolor: alpha(theme.palette.info.light, 0.05),
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'space-between',
              }}
            >
              <Typography variant="subtitle1" fontWeight={500}>
                <TimelineIcon
                  sx={{ mr: 1, fontSize: 18, verticalAlign: 'text-bottom' }}
                />
                Check-in Report: {formattedDate}
              </Typography>

              {activeFiltersCount > 0 && (
                <Chip
                  size="small"
                  label={`${activeFiltersCount} filters`}
                  onDelete={clearFilters}
                  color="primary"
                  variant="outlined"
                />
              )}
            </Box>

            <Box sx={{ p: 2 }}>
              <HrDashboardCard timestamp={timestamp} />
            </Box>
          </Card>
        </Fade>
      );
    }

    // Daily reports view
    return (
      <Stack spacing={2}>
        {timestamp?.rows?.length > 0 ? (
          timestamp.rows.map((row, index) => (
            <Fade key={index} in={true} timeout={200 + index * 50}>
              <Card
                elevation={0}
                sx={{
                  borderRadius: 1,
                  border: '1px solid',
                  borderColor: 'divider',
                }}
              >
                <Box
                  sx={{
                    p: 1.5,
                    borderBottom: '1px solid',
                    borderColor: 'divider',
                    bgcolor: alpha(
                      theme.palette[reportTypes[selectedIndex].color].light,
                      0.05,
                    ),
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'space-between',
                  }}
                >
                  <Typography variant="subtitle1" fontWeight={500}>
                    {React.cloneElement(reportTypes[selectedIndex].icon, {
                      sx: { mr: 1, fontSize: 18, verticalAlign: 'text-bottom' },
                      color: reportTypes[selectedIndex].color,
                    })}
                    {row.project_name || 'Unnamed Project'}
                  </Typography>

                  <Chip
                    label={`${row.count || 0} people`}
                    color={reportTypes[selectedIndex].color}
                    variant="outlined"
                    size="small"
                  />
                </Box>

                <HrcheckinListReportDailyByproject
                  timestamp={row}
                  showSalary={selectedIndex === 1}
                />
              </Card>
            </Fade>
          ))
        ) : (
          <Card
            elevation={0}
            sx={{
              p: 3,
              borderRadius: 1,
              textAlign: 'center',
              border: '1px dashed',
              borderColor: 'divider',
            }}
          >
            <Typography variant="body1" color="text.secondary">
              No data found for {formattedDate}
            </Typography>
          </Card>
        )}
      </Stack>
    );
  };

  // Main render
  if (!timestamp?.isLoading && timestamp?.isCompleted) {
    return (
      <div>
        <Box>
          <ViewTitle title={title} subtitle={subtitle} />
        </Box>

        {renderCompactHeader()}
        {renderTable()}
      </div>
    );
  } else return <Loading isLoading />;
}
